export type Block =
	| { kind: 'text'; html: string }
	| { kind: 'pre'; text: string }
	| { kind: 'lcd'; lines: string[]; frags?: Record<string, string> }
	| { kind: 'colors'; rows: string[] }
	| { kind: 'glyph'; lines: string[]; axis?: boolean }
	| { kind: 'figure'; svg: string; caption?: string };

export interface Problem {
	id: string;
	chip: string;
	blocks: Block[];
	type: 'text' | 'choice';
	answers?: string[];
	choices?: string[];
	answerIndex?: number;
	/** 발견형 퍼즐은 3단 힌트 필수. 상식 퀴즈(trivia)는 힌트 없음. */
	hints?: [string, string, string];
	explain: string;
	/** 상식 퀴즈 여부 (발견형 퍼즐과 구분) */
	trivia?: boolean;
	/** 상식 퀴즈 카테고리 (지리/한국사/과학 등) */
	category?: string;
	/** 상식 퀴즈 난이도 등급 */
	grade?: Grade;
}

/** 상식 퀴즈 난이도 등급 */
export type Grade = '초등' | '중등' | '고등' | '어른';

export const GRADES: { key: Grade; label: string }[] = [
	{ key: '초등', label: '초등' },
	{ key: '중등', label: '중등' },
	{ key: '고등', label: '고등' },
	{ key: '어른', label: '어른' }
];

/** 발견형 분야 — 35개 chip을 6개 상위 분야로 묶어 탐색·태깅에 쓴다.
 *  chip은 개별 문제의 세부 유형이고, field는 그 상위 카테고리다. */
export type DiscoverField = '수·연산' | '언어·문자' | '달력·시간' | '규칙·분류' | '도형·전광판' | '관찰·추리';

