/** chip → 상위 분야. 매핑에 없는 chip은 '관찰·추리'로 떨어뜨린다(안전 기본값). */
export function fieldOfChip(chip: string): DiscoverField {
	return CHIP_FIELD[chip] ?? '관찰·추리';
}

